 * 将 trace 转为 paused 状态。
 * 用于用户主动暂停的场景。
 */
export function transitionToPaused(traceId: string): Trace | null {
  const trace = getTraceById(traceId);          // line 709 — re-fetch for state check
  if (!trace) {
    return null;
  }

  // Only allows pausing from 'running' or 'in_progress'
  if (trace.status !== 'running' && trace.status !== 'in_progress') {  // line 714
    return null;
  }

  const updated = updateTrace(traceId, { status: 'paused' });   // line 718
  console.log(`[traceService] transitionToPaused: ${traceId}`); // line 719
  return updated;
}
