register("agentlog.pauseTrace", async (item: unknown) => {
  let traceId: string | undefined;

  if (item instanceof TraceItem) {
    traceId = item.trace.id;
  }

  if (!traceId) {
    vscode.window.showErrorMessage("无法解析 Trace ID");
    return;
  }

  try {
    const client = getBackendClient();
    await client.pauseTrace(traceId);   // <-- calls the API method above
    traceTreeProvider.refresh();
    vscode.window.showInformationMessage("✅ Trace 已暂停");
  } catch (err) {
    vscode.window.showErrorMessage(
      `暂停失败：${err instanceof Error ? err.message : String(err)}`,
    );
  }
});
```

This registers the `agentlog.pauseTrace` VS Code command. When triggered (e.g. from the tree view context menu on a `TraceItem`), it extracts the trace ID, calls `client.pauseTrace(traceId)`, and refreshes the tree view on success.

